import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.CE5oItKu.js";const u=JSON.parse('{"title":"版本化发布规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/09-versioning.md","filePath":"mango-pmo/rules/backend/09-versioning.md"}'),o={name:"mango-pmo/rules/backend/09-versioning.md"};function n(r,a,s,d,p,c){return i(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="版本化发布规范" tabindex="-1">版本化发布规范 <a class="header-anchor" href="#版本化发布规范" aria-label="Permalink to &quot;版本化发布规范&quot;">​</a></h1><h2 id="_1-适用范围" tabindex="-1">1. 适用范围 <a class="header-anchor" href="#_1-适用范围" aria-label="Permalink to &quot;1. 适用范围&quot;">​</a></h2><p>适用于存在发布态和历史版本的领域对象，例如编号规则、流程定义、模板配置、计费规则、审批规则等。</p><p>只要已发布内容会影响业务记录、外部单据、审计追踪或运行时行为，就必须按本规范处理历史版本。</p><h2 id="_2-基本模型" tabindex="-1">2. 基本模型 <a class="header-anchor" href="#_2-基本模型" aria-label="Permalink to &quot;2. 基本模型&quot;">​</a></h2><ul><li>版本号必须单调递增，不复用、不回退。</li><li>历史版本是不可变快照，发布后不得原地修改。</li><li>当前生效版本只能有一个。</li><li>草稿版本可以编辑，发布后进入生效或历史状态。</li></ul><p>推荐状态：</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td><code>DRAFT</code></td><td>草稿，可编辑，未生效</td></tr><tr><td><code>ACTIVE</code></td><td>当前生效版本</td></tr><tr><td><code>HISTORY</code></td><td>历史版本，不可编辑</td></tr></tbody></table><h2 id="_3-默认回滚策略" tabindex="-1">3. 默认回滚策略 <a class="header-anchor" href="#_3-默认回滚策略" aria-label="Permalink to &quot;3. 默认回滚策略&quot;">​</a></h2><p>历史版本切换或回滚，默认采用：</p><ol><li>选择一个历史版本。</li><li>复制该历史版本的完整配置，生成一个新的草稿版本。</li><li>新版本号取当前最大版本号加一。</li><li>按正常发布流程发布新版本。</li><li>原生效版本转为历史版本，新版本成为生效版本。</li></ol><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前：V1 HISTORY，V2 ACTIVE</span></span>
<span class="line"><span>切换到 V1</span></span>
<span class="line"><span>结果：V1 HISTORY，V2 HISTORY，V3 ACTIVE</span></span>
<span class="line"><span>说明：V3 的内容复制自 V1</span></span></code></pre></div><p>这样可以保证回滚本身也是一次可审计的发布动作。</p><h2 id="_4-禁止做法" tabindex="-1">4. 禁止做法 <a class="header-anchor" href="#_4-禁止做法" aria-label="Permalink to &quot;4. 禁止做法&quot;">​</a></h2><ul><li>禁止直接把当前版本指针改回历史版本作为默认回滚方案。</li><li>禁止修改历史版本内容来模拟回滚。</li><li>禁止回退版本号。</li><li>禁止回滚已经生成的业务数据、流水值、单据号、外部记录。</li><li>禁止把发布态、历史态和草稿态混在同一条可变记录里。</li></ul><h2 id="_5-直接切指针例外" tabindex="-1">5. 直接切指针例外 <a class="header-anchor" href="#_5-直接切指针例外" aria-label="Permalink to &quot;5. 直接切指针例外&quot;">​</a></h2><p>只有满足以下低风险场景时，才允许直接切换指针：</p><ul><li>非业务关键配置。</li><li>运行环境部署指针，例如灰度、蓝绿、镜像版本。</li><li>A/B 策略或 Feature Flag。</li><li>不要求严格审计。</li><li>紧急恢复场景，且必须补充审计记录和原因说明。</li></ul><p>涉及业务单据、金额、权限、审批、编号、合同、外部集成结果的场景，不使用直接切指针。</p><h2 id="_6-数据要求" tabindex="-1">6. 数据要求 <a class="header-anchor" href="#_6-数据要求" aria-label="Permalink to &quot;6. 数据要求&quot;">​</a></h2><p>版本主表至少需要表达：</p><ul><li>业务对象标识。</li><li>版本号。</li><li>版本状态。</li><li>发布时间。</li><li>发布人。</li></ul><p>按需要增加：</p><ul><li>来源版本号，例如 <code>source_version</code>。</li><li>来源记录 ID，例如 <code>source_id</code>。</li><li>发布原因，例如 <code>publish_reason</code>。</li><li>当前生效标识或唯一约束，保证同一业务对象只有一个生效版本。</li></ul><p>版本明细表必须跟随版本快照保存，不能读取可变的当前配置作为历史内容。</p><h2 id="_7-测试要求" tabindex="-1">7. 测试要求 <a class="header-anchor" href="#_7-测试要求" aria-label="Permalink to &quot;7. 测试要求&quot;">​</a></h2><p>涉及版本化发布时，必须覆盖：</p><ul><li>新增草稿。</li><li>编辑草稿。</li><li>发布后旧版本变历史、新版本变生效。</li><li>从历史版本复制生成新版本。</li><li>历史版本不可原地修改。</li><li>同一业务对象不能同时存在多个生效版本。</li><li>业务生成结果不因版本回滚而被回滚。</li></ul>`,29)])])}const _=l(o,[["render",n]]);export{u as __pageData,_ as default};
